/*
 * A generalized callback
 */
export type Callback = (error?: Error | string, data?: any) => void;

/*
 * A default empty implementation of a callback
 */
export const EmptyCallback: Callback = () => { return; };

class Async {

    /**
     * Turns a node style callback into an async Promise. For example
     * ```
     * import fs = require('fs');
     * async function getContents(path:string):Promise<string> {
     *      const contents:string = await Async.get<string>(cb => fs.readFile(path, cb));
     *      return contents;
     * }
     * ```
     */
    static async get<T>(exec:(cb:(error:Error|string, data?:T) => void) => void):Promise<T> {
        return new Promise<T>((resolve:(data:T) => void, reject:(error:Error|string) => void) => {
            exec((error:Error|string, data:T) => {
                if(error) {
                    return reject(error);
                }
                resolve(data);
            });
        });
    }

    /**
     * Turns a function with a callback into an async Promise. The difference is that
     * this callback does not expect a node style callback like `(error:Error, data:T) => void`.
     * Instead it expects `(data:T) => void`.
     */
    static async get2<T>(exec:(cb:(data?:T) => void) => void):Promise<T> {
        return new Promise<T>((resolve:(data:T) => void) => {
            exec((data:T) => {
                resolve(data);
            });
        });
    }

    /**
     * Same a Promise.all, except it will only run a max number of promises
     * in parallel at a time. This is useful for CPU heavy operations.
     * @param  {Promise[]} promises The array of promises
     * @param  {number}         max      Max number of promises that can be run in parallel.
     * @return {Promise[]}          An array of results.
     */
    static async all(promises:Promise<any>[], max?:number):Promise<any[]> {
        let results:any[] = [];
        while(promises.length > 0) {
            const temp:any[] = await Promise.all(promises.splice(0, max));
            results = results.concat(temp);
        }
        return results;
    }
}

export default Async;
