import path = require('path');
import findRoot = require('find-root');
import {SystemManagerClient, SkillRecord} from 'jibo-client-framework';
import {Log} from 'jibo-log';
import log from '../../log';

Log.processName = "ssm";


class MainProcess {

    constructor() {
        //TODO: REMOVE DEPRECATION
        //if still running in electron, do everything in the renderer process instead
        if (process.versions['electron'] && !global['window']) {
            const root = findRoot(__dirname);
            require(path.join(root, 'startup/deprecated'));
            return;
        }
        SystemManagerClient.createInstance('127.0.0.1', 8585);
        log.debug('Started');
        this.killRunningSkills();
    }

    private killRunningSkills() {
        log.info('Checking for running skills');
        SystemManagerClient.instance.list((err:Error, records:Array<SkillRecord>) => {
            if(err) {
                log.warn('System Manager error. Now initializing SSM.', err);
                return this.makeSSM();
            }
            for(let i = 0; i < records.length; i++) {
                if(records[i].running) {
                    log.info('Terminating ', records[i].name);
                    SystemManagerClient.instance.terminate(records[i].name, (err:Error) => {
                        log.info('Initializing SSM');
                        this.makeSSM();
                    });
                    return;
                }
            }
            log.info('No skill to shut down. Initializing SSM');
            this.makeSSM();
        });
    }

    /**
     * Called when the main process is ready
     */
    private makeSSM():void {
        log.debug('makeSSM');
        const root = findRoot(__dirname);
        const TcpProxy = require(path.join(root, 'lib/skills-service-manager')).default.TcpProxy;
        new TcpProxy(9222, 9191).start();
        //TODO: REMOVE DEPRECATION
        //if still running in electron, set up a proxy for the renderer process debugging
        if (process.versions['electron']) {
            new TcpProxy(10223, 12345).start();
        }
        require(path.join(root, 'startup'));
    }
}

export default function() {
    return new MainProcess();
}
