import path = require('path');
import {WSClient, ServiceOptions, JiboServerRequest,
	JiboServerResponse, HTTPService} from 'jibo-service-framework';
import fs = require('fs');
import Async from '../../../utils/Async';
import Router = require("router");
import {RegistryClient} from 'jibo-service-framework';
import {SSMService} from '../../../SSMService';


interface Process {
    cmdname:string;
    name:string;
    ppid:number;
    tid:number;
    utime:number;
    vm_rss:number;
    vsize:number;
}

interface ProcessFrame {
    type:'processes';
    ts:number;
    total_cpu_jiffies:string;
    data:Process[];
}

interface EventFrame {
    type:'event';
    ts:number;
    data:string;
}

type Frame = ProcessFrame | EventFrame;

interface Processes {
    total_cpu_jiffies:string;
    processes:Process[];
}

const processes:string[] = [
    'electron',
    'jibo',
    'pulseaudio',
    'lib/expression-process'
];

const logDir:string = '/var/log';
const logPath:string = path.join(logDir, 'monitoring.log');

class ReporterService extends HTTPService implements SSMService {

    private static _instance:ReporterService;

    private client:WSClient;
    private stopped:boolean = false;
    private initialized:boolean = false;


    public static get instance():ReporterService {
        return ReporterService._instance;
    }

    public async init(callback?:(err?:Error) => void) {

        RegistryClient.createInstance('127.0.0.1', 8181);
        await Async.get<void>(cb => super.init(cb));
        this.client = new WSClient(`ws://127.0.0.1:4111/info/process`);
        this.initialized = true;
        const oldLogPath:string = path.join(logDir, `monitoring-${Date.now()}.log`);
        const exists:boolean = await Async.get2<boolean>(cb => fs.exists(logPath, cb));
        if(exists) {
            await Async.get<void>(cb => fs.rename(logPath, oldLogPath, cb));
        }
        callback();
        this.start();
    }

    public routes(url:Router) {
        super.routes(url);
        url.post('/report', this.addReport);
    }

    public async addReport(req:JiboServerRequest, res:JiboServerResponse):Promise<void> {
        const frame:Frame = await this.parseRequest(req);
        await Async.get<void>(cb => fs.appendFile(logPath, JSON.stringify(frame) + '\n', cb));
    }

    public async addEvent(eventName:string):Promise<void> {
        if(!this.initialized) {
            return;
        }
        const frame:EventFrame = {
            type: 'event',
            ts: Date.now(),
            data: eventName
        };
        await Async.get<void>(cb => fs.appendFile(logPath, JSON.stringify(frame) + '\n', cb));
    }

    public stop():void {
        this.stopped = true;
    }

    constructor(options:ServiceOptions, rootDir) {
        super('monitor-reporter', options, rootDir);
        if (ReporterService._instance) {
            throw new Error('Cannot instantiate ReporterService more than once');
        }
        ReporterService._instance = this;
        this.addReport = this.addReport.bind(this);
    }

    private async start():Promise<void> {
        while(!this.stopped) {
            const data:Processes = await Async.get2<Processes>(cb => this.client.once('message', cb));
            const frame:ProcessFrame = {
                type: 'processes',
                ts: Date.now(),
                total_cpu_jiffies: data.total_cpu_jiffies,
                data: []
            };
            for(let i = 0; i < data.processes.length; i++) {
                const process:Process = data.processes[i];
                for(let j = 0; j < processes.length; j++) {
                    if (process.cmdname.indexOf(processes[j]) >= 0) {
                        (frame.data as Process[]).push(process);
                    }
                }
            }
            await Async.get<void>(cb => fs.appendFile(logPath, JSON.stringify(frame) + '\n', cb));
        }
    }

    private parseRequest(req:JiboServerRequest):Promise<any> {
        return new Promise<any>((resolve, reject) => {
            let body = "";
            req.on('data', (chunk) => {
                body += chunk;
            });
            req.on('end', () => {
                let data:any;
                try {
                    data = JSON.parse(body);
                    resolve(data);
                }
                catch(e) {
                    reject(e);
                }
            });
        });
    }

}


export default ReporterService;
