import createMain from './MainProcess';
import ReporterService from './reporter/ReporterService';
import Async from '../../utils/Async';
import {instantiateService} from '../../SSMService';

async function start():Promise<void> {
    if(process.argv[3] === '--reporter') {
        instantiateService(ReporterService, {port: 10101}, 'reporter-service');
        await Async.get<void>(cb => ReporterService.instance.init(cb));
    }
    console.log('pre create main');
    createMain();
}

start();
